            .padding(6)
            .glassEffect(.regular, in: .capsule)
        }
        .padding(.horizontal, 24)
    }

    @ViewBuilder
    private func tabButton(for tab: LiquidGlassTab, at index: Int) -> some View {
        let isSelected = selection == index
        Button {
            if reduceMotion {
                selection = index
            } else {
                withAnimation(.smooth(duration: 0.35)) { selection = index }
            }
        } label: {
            VStack(spacing: 3) {
                Image(systemName: tab.systemImage)
                    .font(.system(size: 18, weight: .semibold))
                    .symbolVariant(isSelected ? .fill : .none)
                Text(tab.title)
                    .font(.system(size: 11, weight: .semibold))
                    .lineLimit(1)
            }
            .foregroundStyle(isSelected ? AnyShapeStyle(tint) : AnyShapeStyle(.secondary))
            .frame(maxWidth: .infinity)
            .padding(.vertical, 8)
            .contentShape(.capsule)
            .background {
                if isSelected {
                    Capsule()
                        .fill(Color.clear)
                        .glassEffect(
                            .regular.tint(tint.opacity(0.22)).interactive(),
                            in: .capsule
                        )
                        .glassEffectID("tab-pill", in: glassNamespace)
                }
            }
        }
        .buttonStyle(.plain)
        .accessibilityLabel(tab.title)
        .accessibilityAddTraits(isSelected ? [.isSelected, .isButton] : .isButton)
    }
}

